(function () {
	'use strict';

	class State {

		static mainSel = '.democracy'
		static screenSel = '.dem-screen'             // result container selector
		static userAnswerSel = '.dem-add-answer-txt' // "free" answer field class

		static $polls
		static $loader
		static loaderTmr

		static ajaxurl

		static answMaxHeight
		static animSpeed
		static lineAnimSpeed

	}

	class Utils {

		// Determine the height when the element uses height:auto
		static detectRealHeight( el ){
			if( ! el.parentElement ){
				return el.getBoundingClientRect().height
			}

			const clone = el.cloneNode( true );
			Object.assign( clone.style, {
				height    : 'auto', maxHeight: 'none',
				position  : 'absolute', left: '-9999px', top: '0', width: window.getComputedStyle( el ).width,
				visibility: 'hidden', pointerEvents: 'none'
			} );

			el.before( clone );

			const cloneStyle = window.getComputedStyle( clone );
			const realHeight = (cloneStyle.boxSizing === 'border-box')
				? parseFloat( cloneStyle.height )
				: clone.getBoundingClientRect().height;

			clone.remove();

			return realHeight
		}

		// Set height explicitly
		static setHeight( el, noanimation ){
			const newH = Utils.detectRealHeight( el );

			if( noanimation ){
				el.style.height = newH + 'px';
			}
			else {
				const duration = State.animSpeed || 0;
				Utils.animateHeight( el, newH, duration );
			}
		}

		/**
		 * @param {HTMLElement} root
		 */
		static setAnswsMaxHeight( root ){
			if( State.answMaxHeight === '-1' || State.answMaxHeight === '0' || ! State.answMaxHeight ){
				return
			}

			const el = root.querySelector( '.dem-vote, .dem-answers' );
			const maxHeight = parseInt( State.answMaxHeight );

			el.style.maxHeight = 'none';
			el.style.overflowY = 'visible';

			const elStyle = window.getComputedStyle( el );
			const elHeight = (elStyle.boxSizing === 'border-box')
				? parseFloat( elStyle.height )
				: el.getBoundingClientRect().height;

			// collapse if above max height and diff > 100px; hiding 100px isn't worth it
			const diff = elHeight - maxHeight;
			if( diff > 100 ){
				el.style.position = 'relative';

				const overlay = Utils.newEl( '<span class="dem__collapser"><span class="arr"></span></span>' );
				el.append( overlay );

				const fn__expand = () => {
					overlay.classList.add( 'expanded' );
					overlay.classList.remove( 'collapsed' );
				};
				const fn__collaps = () => {
					overlay.classList.add( 'collapsed' );
					overlay.classList.remove( 'expanded' );
				};
				let timeout;

				// don't collapse if it was expanded
				const isExpanded = root.dataset['expanded'] === 'true';
				if( isExpanded ){
					fn__expand();
				}
				else {
					fn__collaps();
					el.style.height = `${ maxHeight }px`;
					el.style.overflowY = 'hidden';
				}

				// trigger click on hover so user doesn't need to click to expand
				overlay.addEventListener( 'mouseenter', function(){
					if( root.dataset['expanded'] !== 'true' ){
						timeout = setTimeout( () => overlay.dispatchEvent( new Event( 'click' ) ), 1000 );
					}
				} );
				overlay.addEventListener( 'mouseleave', function(){
					clearTimeout( timeout );
				} );

				overlay.addEventListener( 'click', function(){
					clearTimeout( timeout );

					// collapse
					if( root.dataset['expanded'] === 'true' ){
						fn__collaps();

						delete root.dataset['expanded'];
						root.style.height = 'auto';
						el.style.overflowY = 'hidden';
						Utils.animateHeight( el, maxHeight, State.animSpeed, () => {
							root.style.height = Utils.detectRealHeight( root ) + 'px';
						} );
					}
					// expand
					else {
						fn__expand();

						// measure height without collapsing
						const newH = Utils.detectRealHeight( el ) + 7; // extra space for "add your answer"

						root.dataset['expanded'] = 'true';
						root.style.height = 'auto';
						Utils.animateHeight( el, newH, State.animSpeed, () => {
							root.style.height = Utils.detectRealHeight( root ) + 'px';
							el.style.overflowY = 'visible';
						} );
					}
				} );
			}

		}

		// max answers limit
		static maxAnswLimitInit(){
			if( Utils.maxAnswLimitBound ){
				return
			}
			Utils.maxAnswLimitBound = true;

			document.addEventListener( 'change', function( event ){
				const target = event.target;
				if( ! (target instanceof HTMLInputElement) || target.type !== 'checkbox' ){
					return
				}

				const poll = target.closest( State.mainSel );
				if( ! poll ){
					return
				}

				poll._maxAnsws ??= parseInt( JSON.parse( poll.dataset['opts'] ).max_answs ) || 0;
				if( ! poll._maxAnsws ){
					return
				}

				const screen = target.closest( State.screenSel );
				if( ! screen ){
					return
				}

				const checkboxes = screen.querySelectorAll( 'input[type="checkbox"]' );
				const checkedCount = screen.querySelectorAll( 'input[type="checkbox"]:checked' ).length;

				// if reached max, disable unchecked
				if( checkedCount >= poll._maxAnsws ){
					checkboxes.forEach( checkbox => {
						if( ! checkbox.checked ){
							checkbox.disabled = true;
							checkbox.closest( 'li' ).classList.add( 'dem-disabled' );
						}
					} );
				}
				// else re-enable all
				else {
					checkboxes.forEach( checkbox => {
						checkbox.disabled = false;
						checkbox.closest( 'li' ).classList.remove( 'dem-disabled' );
					} );
				}
			} );
		}

		static demShake( el ){
			const position = window.getComputedStyle( el ).position;
			if( ! position || position === 'static' ){
				el.style.position = 'relative';
			}

			const keyframes = [
				{ left: '0px' },
				{ left: '-10px', offset: 0.2 },
				{ left: '10px', offset: 0.40 },
				{ left: '-10px', offset: 0.60 },
				{ left: '10px', offset: 0.80 },
				{ left: '0px', offset: 1 }
			];
			const timing = { duration: 500, iterations: 1, easing: 'linear' };
			el.animate( keyframes, timing );
		}

		// dots loading animation: ...
		static loadingDots( el ){
			const isInput = (el.tagName.toLowerCase() === 'input');
			const str = isInput ? el.value : el.innerHTML;

			if( str.slice( -3 ) === '...' ){
				el[isInput ? 'value' : 'innerHTML'] = str.slice( 0, -3 );
			}
			else {
				el[isInput ? 'value' : 'innerHTML'] += '.';
			}

			State.loaderTmr = setTimeout( () => Utils.loadingDots( el ), 200 );
		}

		static animateHeight( el, toHeight, duration, onFinish ){
			const fromHeight = el.getBoundingClientRect().height;
			if( el._heightAnim ){
				el._heightAnim.cancel();
			}

			if( ! duration ){
				el.style.height = toHeight + `px`;
				onFinish && onFinish();
				return
			}

			const anim = el.animate(
				[{ height: `${ fromHeight }px` }, { height: `${ toHeight }px` }],
				{ duration, easing: 'ease-out', fill: 'forwards' }
			);
			el._heightAnim = anim;
			anim.onfinish = () => {
				el.style.height = toHeight + `px`;
				delete el._heightAnim;
				onFinish && onFinish();
			};
			anim.oncancel = () => {
				delete el._heightAnim;
			};
		}

		/**
		 * Creates HTML element from passed string.
		 *
		 * Example: create_html_element( `<div class="kama-lightbox"/>` )
		 *
		 * @param {string} str
		 * @return {HTMLElement}
		 */
		static newEl( str ){
			let div = document.createElement( 'div' );
			div.innerHTML = str.trim();

			return div.firstChild
		}

	}

	class Loader {

		static setLoader( target ){
			if( State.$loader ){
				const loaderClone = State.$loader.cloneNode( true );
				loaderClone.style.display = 'table';

				const screen = target.closest( State.screenSel );
				if( screen ){
					screen.append( loaderClone );
				}
			}
			else {
				State.loaderTmr = setTimeout( () => Utils.loadingDots( target ), 50 );
			}
		}

		static unsetLoader( target ){
			if( State.$loader ){
				const screen = target.closest( State.screenSel );
				screen.querySelectorAll( '.dem-loader' ).forEach( node => node.remove() );
			}
			else {
				clearTimeout( State.loaderTmr );
			}
		}

	}

	/*! js-cookie v3.0.5 | MIT */
	/* eslint-disable no-var */
	function assign (target) {
	  for (var i = 1; i < arguments.length; i++) {
	    var source = arguments[i];
	    for (var key in source) {
	      target[key] = source[key];
	    }
	  }
	  return target
	}
	/* eslint-enable no-var */

	/* eslint-disable no-var */
	var defaultConverter = {
	  read: function (value) {
	    if (value[0] === '"') {
	      value = value.slice(1, -1);
	    }
	    return value.replace(/(%[\dA-F]{2})+/gi, decodeURIComponent)
	  },
	  write: function (value) {
	    return encodeURIComponent(value).replace(
	      /%(2[346BF]|3[AC-F]|40|5[BDE]|60|7[BCD])/g,
	      decodeURIComponent
	    )
	  }
	};
	/* eslint-enable no-var */

	/* eslint-disable no-var */

	function init (converter, defaultAttributes) {
	  function set (name, value, attributes) {
	    if (typeof document === 'undefined') {
	      return
	    }

	    attributes = assign({}, defaultAttributes, attributes);

	    if (typeof attributes.expires === 'number') {
	      attributes.expires = new Date(Date.now() + attributes.expires * 864e5);
	    }
	    if (attributes.expires) {
	      attributes.expires = attributes.expires.toUTCString();
	    }

	    name = encodeURIComponent(name)
	      .replace(/%(2[346B]|5E|60|7C)/g, decodeURIComponent)
	      .replace(/[()]/g, escape);

	    var stringifiedAttributes = '';
	    for (var attributeName in attributes) {
	      if (!attributes[attributeName]) {
	        continue
	      }

	      stringifiedAttributes += '; ' + attributeName;

	      if (attributes[attributeName] === true) {
	        continue
	      }

	      // Considers RFC 6265 section 5.2:
	      // ...
	      // 3.  If the remaining unparsed-attributes contains a %x3B (";")
	      //     character:
	      // Consume the characters of the unparsed-attributes up to,
	      // not including, the first %x3B (";") character.
	      // ...
	      stringifiedAttributes += '=' + attributes[attributeName].split(';')[0];
	    }

	    return (document.cookie =
	      name + '=' + converter.write(value, name) + stringifiedAttributes)
	  }

	  function get (name) {
	    if (typeof document === 'undefined' || (arguments.length && !name)) {
	      return
	    }

	    // To prevent the for loop in the first place assign an empty array
	    // in case there are no cookies at all.
	    var cookies = document.cookie ? document.cookie.split('; ') : [];
	    var jar = {};
	    for (var i = 0; i < cookies.length; i++) {
	      var parts = cookies[i].split('=');
	      var value = parts.slice(1).join('=');

	      try {
	        var found = decodeURIComponent(parts[0]);
	        jar[found] = converter.read(value, found);

	        if (name === found) {
	          break
	        }
	      } catch (e) {}
	    }

	    return name ? jar[name] : jar
	  }

	  return Object.create(
	    {
	      set,
	      get,
	      remove: function (name, attributes) {
	        set(
	          name,
	          '',
	          assign({}, attributes, {
	            expires: -1
	          })
	        );
	      },
	      withAttributes: function (attributes) {
	        return init(this.converter, assign({}, this.attributes, attributes))
	      },
	      withConverter: function (converter) {
	        return init(assign({}, this.converter, converter), this.attributes)
	      }
	    },
	    {
	      attributes: { value: Object.freeze(defaultAttributes) },
	      converter: { value: Object.freeze(converter) }
	    }
	  )
	}

	var api = init(defaultConverter, { path: '/' });

	class Cache {

		static actionsHandler

		static initAll(){
			const cacheBlocks = document.querySelectorAll( '.dem-cache-screens' );
			if( ! cacheBlocks.length ){
				return
			}

			cacheBlocks.forEach( cacheBlock => Cache.initCache( cacheBlock ) );
		}

		static initCache( cacheBlock ){
			const dem = Cache.findMainBlock( cacheBlock );
			if( ! dem ){
				console.warn( 'Democracy: Main dem div not found' );
				return
			}

			const screen = dem.querySelector( State.screenSel );
			if( ! screen ){
				return
			}

			const demOpts = Cache.getOpts( dem );
			const demId = demOpts.pid;
			const answrs = api.get( 'demPoll_' + demId );
			const notVoteFlag = answrs === 'notVote'; // If we already checked that user hasn't voted, don't request again
			const isAnswrs = typeof answrs !== 'undefined' && ! notVoteFlag;

			// choose which screen to show and how to handle it
			const voteBlock = cacheBlock.querySelector( State.screenSel + '-cache.vote' );
			const votedBlock = cacheBlock.querySelector( State.screenSel + '-cache.voted' );
			const voteHTML = voteBlock ? voteBlock.innerHTML : '';
			const votedHTML = votedBlock ? votedBlock.innerHTML : '';

			// if poll is closed, only results should be cached. Exit.
			if( ! voteHTML ){
				return
			}

			// apply cached view
			// if results view is available
			const setVoted = isAnswrs && votedHTML;
			screen.innerHTML = (setVoted ? votedHTML : voteHTML) + '<!--cache-->';
			screen.classList.remove( 'vote', 'voted' );
			screen.classList.add( setVoted ? 'voted' : 'vote' );

			if( isAnswrs ){
				Cache.setAnswers( screen, answrs );
			}

			Cache.actionsHandler( screen, true );

			if( notVoteFlag ){
				return // exit if it has already been checked that the user has not voted.
			}

			// If there are no votes in cookies and the plugin option keep_logs is enabled,
			// send a request to the database for checking, by event (mouse over a block).
			if( ! isAnswrs && parseInt( cacheBlock.dataset.opt_logs, 10 ) === 1 ){
				let tmout;
				const notcheck__fn = function(){
					clearTimeout( tmout );
				};
				const check__fn = function(){
					tmout = setTimeout( function(){
						// Run once!
						if( dem.classList.contains( 'checkAnswDone' ) ){
							return
						}

						dem.classList.add( 'checkAnswDone' );

						const forDotsLoader = dem.querySelector( '.dem-link' );
						if( forDotsLoader ){
							Loader.setLoader( forDotsLoader );
						}

						Cache.post( State.ajaxurl, {
							dem_pid: demId,
							dem_act: 'getVotedIds',
							action : 'dem_ajax'
						} )
							.then( reply => {
								if( forDotsLoader ){
									Loader.unsetLoader( forDotsLoader );
								}

								// exit if there are no answers
								if( ! reply ){
									return
								}

								screen.innerHTML = votedHTML;
								Cache.setAnswers( screen, reply );

								Cache.actionsHandler( screen );

								// a message that you have voted or for users only
								Cache.showNotice( screen, reply );
							} );
					}, 700 );
					// 700 for optimization, so that the request is not sent instantly if you just swipe the mouse on the survey...
				};

				// hover
				dem.addEventListener( 'mouseenter', check__fn );
				dem.addEventListener( 'mouseleave', notcheck__fn );
				dem.addEventListener( 'click', check__fn );
			}
		}

		static showNotice( screen, type ){
			let notice = screen.querySelector( '.dem-youarevote' ); // "already voted"

			// If only logged-in users can vote
			if( type === 'blocked_because_not_logged_note' ){
				const revoteBtn = screen.querySelector( '.dem-revote-button' );
				if( revoteBtn ){
					revoteBtn.remove();
				}

				notice = screen.querySelector( '.dem-only-users' );
			}

			if( ! notice ){
				return
			}

			Cache.showElement( notice );
			screen.prepend( notice );
			// hide
			setTimeout( () => Cache.slideUp( notice, 600 ), 10000 );
		}

		// set user's answers in results/vote block
		static setAnswers( screen, answrs ){
			const aids = answrs.split( /,/ ).filter( aid => aid !== '' );

			// results view
			if( screen.classList.contains( 'voted' ) ){
				const dema = screen.querySelector( '.dem-answers' );
				const votedClass = dema ? dema.dataset.votedClass : '';
				const votedtxt = dema ? dema.dataset.votedTxt : '';

				aids.forEach( aid => {
					const nodes = Cache.queryAidNodes( screen, aid );
					nodes.forEach( node => {
						if( votedClass ){
							node.classList.add( votedClass );
						}

						const title = node.getAttribute( 'title' ) || '';
						if( votedtxt ){
							node.setAttribute( 'title', votedtxt + title );
						}
					} );
				} );

				// remove "Vote" button
				screen.querySelectorAll( '.dem-vote-link' ).forEach( node => node.remove() );
			}
			// voting view
			else {
				const answerNodes = Array.from( screen.querySelectorAll( '[data-aid]' ) );
				const btnVoted = screen.querySelector( '.dem-voted-button' );

				// set answers
				aids.forEach( aid => {
					const nodes = Cache.queryAidNodes( screen, aid );
					nodes.forEach( node => {
						node.querySelectorAll( 'input' ).forEach( input => {
							input.checked = true;
						} );
					} );
				} );

				// disable all
				answerNodes.forEach( node => {
					node.querySelectorAll( 'input' ).forEach( input => {
						input.disabled = true;
					} );
				} );

				// remove voting button
				screen.querySelectorAll( '.dem-vote-button' ).forEach( node => node.remove() );
				//screen.querySelectorAll( '[data-dem-act="vote"]' ).forEach( node => node.remove() )

				// if "already voted" button exists, revote is disabled
				if( btnVoted ){
					Cache.showElement( btnVoted );
				}
				// show revote button
				else {
					screen.querySelectorAll( 'input[value="vote"]' ).forEach( node => node.remove() ); // allow revote
					screen.querySelectorAll( '.dem-revote-button-wrap' ).forEach( node => Cache.showElement( node ) );
				}
			}
		}

		static findMainBlock( cacheBlock ){
			let prev = cacheBlock.previousElementSibling;
			while( prev ){
				if( prev.matches( State.mainSel ) ){
					return prev
				}
				prev = prev.previousElementSibling;
			}

			return cacheBlock.closest( State.mainSel )
		}

		static getOpts( el ){
			const raw = el.dataset.opts;
			if( ! raw ){
				return {}
			}

			try{
				return JSON.parse( raw )
			}
			catch( e ){
				return {}
			}
		}

		static queryAidNodes( screen, aid ){
			const safeAid = (window.CSS && CSS.escape) ? CSS.escape( aid ) : aid;
			return Array.from( screen.querySelectorAll( '[data-aid="' + safeAid + '"]' ) )
		}

		static showElement( el ){
			el.hidden = false;
			if( getComputedStyle( el ).display === 'none' ){
				el.style.display = 'block';
			}
			else if( el.style.display === 'none' ){
				el.style.display = '';
			}
		}

		static slideUp( el, duration ){
			const height = el.getBoundingClientRect().height;
			if( ! height ){
				el.style.display = 'none';
				return
			}

			el.style.overflow = 'hidden';
			el.style.height = height + 'px';
			el.style.transition = 'height ' + duration + 'ms ease';

			requestAnimationFrame( () => {
				el.style.height = '0px';
			} );

			const cleanup = () => {
				el.style.display = 'none';
				el.style.overflow = '';
				el.style.height = '';
				el.style.transition = '';
				el.removeEventListener( 'transitionend', cleanup );
			};

			el.addEventListener( 'transitionend', cleanup );
			setTimeout( cleanup, duration + 50 );
		}

		static post( url, data ){
			const body = new URLSearchParams();
			Object.keys( data ).forEach( key => body.append( key, data[ key ] ) );

			return fetch( url, {
				method: 'POST',
				credentials: 'same-origin',
				headers: {
					'Content-Type': 'application/x-www-form-urlencoded; charset=UTF-8'
				},
				body
			} )
				.then( response => response.text() )
				.catch( () => '' )
		}

	}

	document.addEventListener( 'DOMContentLoaded', democracyInit );

	function democracyInit(){
		State.$polls = jQuery( State.mainSel );
		if( ! State.$polls.length ){
			return
		}

		State.$loader = document.querySelector( '.dem-loader' );

		const opts = State.$polls.first().data( 'opts' );
		State.ajaxurl = opts.ajax_url;
		State.answMaxHeight = opts.answs_max_height;
		State.animSpeed = parseInt( opts.anim_speed );
		State.lineAnimSpeed = parseInt( opts.line_anim_speed );

		queueMicrotask( init ); // wait for functions

		function init(){
			// Core Democracy events for all blocks
			const $demScreens = State.$polls.find( State.screenSel ).filter( ':visible' );
			const demScreensSetHeight = function(){
				$demScreens.each( function(){
					this.style.height = Utils.detectRealHeight( this ) + 'px';
				} );
			};

			$demScreens.demInitActions( 1 );

			window.addEventListener( 'resize', demScreensSetHeight ); // update height on resize

			window.addEventListener( 'load', demScreensSetHeight ); // update height once more

			Utils.maxAnswLimitInit(); // limit for multi-answer selection

			/*
			 * Cache handling.
			 * Requires js-cookie to be installed
			 * and extra Democracy variables/methods.
			 */
			Cache.actionsHandler = ( screen, noanimation ) => jQuery( screen ).demInitActions( noanimation );
			Cache.initAll();
		}

		// Initialize all events for each poll: clicks, height, button visibility
		// applies to '.dem-screen'
		jQuery.fn.demInitActions = function( noanimation ){

			return this.each( function(){
				// Attach click handlers for all marked elements inside the given element:
				// includes AJAX on click and other Democracy interactions ----------
				const $this = jQuery( this );
				const attr = 'data-dem-act';

				$this.find( '[' + attr + ']' ).each( function(){
					const $the = jQuery( this );
					$the.attr( 'href', '' ); // clear URL so the request URL isn't visible

					$the.on( 'click', function( e ){
						e.preventDefault();
						$the.blur().demDoAction( $the.attr( attr ) );
					} );
				} );

				// Hide the submit button where needed ------------
				const autoVote = !! $this.find( 'input[type=radio][data-dem-act=vote]' ).first().length;
				if( autoVote ) $this.find( '.dem-vote-button' ).hide();

				// collapse content if there are too many answers
				Utils.setAnswsMaxHeight( $this[0] );

				// animate filled bars - line_animation
				if( State.lineAnimSpeed ){
					$this.find( '.dem-fill' ).each( function(){
						const $fill = jQuery( this );
						//setTimeout(function(){ fill.style.width = was; }, State.animSpeed + 500); // based on CSS transition; also fires on reset and interferes...
						setTimeout( function(){
							$fill.animate( { width: $fill.data( 'width' ) }, State.lineAnimSpeed );
						}, State.animSpeed, 'linear' );
					} );
				}

				// Set height explicitly ------------
				// Bind to window resize (mobile rotation, etc.)
				Utils.setHeight( this, noanimation );

				// form submit event
				$this.find( 'form' ).on( 'submit', function( e ){
					e.preventDefault();

					const act = jQuery( this ).find( 'input[name="dem_act"]' ).val();
					if( act )
						jQuery( this ).demDoAction( jQuery( this ).find( 'input[name="dem_act"]' ).val() );
				} );
			} )
		};


		// Add user answer (link)
		jQuery.fn.demAddAnswer = function(){

			const $the = this.first();
			const $demScreen = $the.closest( State.screenSel );
			const isMultiple = $demScreen.find( '[type=checkbox]' ).length > 0;
			const $input = jQuery( '<input type="text" class="' + State.userAnswerSel.replace( /\./, '' ) + '" value="">' ); // input for adding an answer

			// show vote button
			$demScreen.find( '.dem-vote-button' ).show();

			// handle radio inputs: uncheck and attach click handler
			$demScreen.find( '[type=radio]' ).each( function(){

				jQuery( this ).on( 'click', function(){
					$the.fadeIn( 300 );
					jQuery( State.userAnswerSel ).remove();
				} );

				if( 'radio' === jQuery( this )[0].type )
					this.checked = false; // uncheck
			} );

			$the.hide().parent( 'li' ).append( $input );
			$input.hide().fadeIn( 300 ).focus(); // animation

			// add a button to remove the user-entered text
			if( isMultiple ){

				const $ua = $demScreen.find( State.userAnswerSel );

				jQuery( '<span class="dem-add-answer-close">×</span>' )
					.insertBefore( $ua )
					.css( 'line-height', $ua.outerHeight() + 'px' )
					.on( 'click', function(){
						const $par = jQuery( this ).parent( 'li' );
						$par.find( 'input' ).remove();
						$par.find( 'a' ).fadeIn( 300 );
						jQuery( this ).remove();
					} );
			}

			return false // !!!
		};

		// Collect answers and return as a string
		jQuery.fn.demCollectAnsw = function(){
			const $form = this.closest( 'form' );
			const $answers = $form.find( '[type=checkbox],[type=radio]' );
			const userText = $form.find( State.userAnswerSel ).val();
			let answ = [];
			const $checkbox = $answers.filter( '[type=checkbox]:checked' );

			// multiple
			if( $checkbox.length > 0 ){
				$checkbox.each( function(){
					answ.push( jQuery( this ).val() );
				} );
			}
			// single
			else {
				const str = $answers.filter( '[type=radio]:checked' );
				if( str.length )
					answ.push( str.val() );
			}

			// user_added
			if( userText ){
				answ.push( userText );
			}

			answ = answ.join( '~' );

			return answ ? answ : ''
		};

		// handle requests on click
		jQuery.fn.demDoAction = function( action ){

			const $the = this.first();
			const $dem = $the.closest( State.mainSel );
			const data = {
				dem_pid: $dem.data( 'opts' ).pid,
				dem_act: action,
				action : 'dem_ajax'
			};

			if( typeof data.dem_pid === 'undefined' ){
				console.warn( 'Poll id is not defined!' );
				return false
			}

			// Collect answers
			if( 'vote' === action ){
				data.answer_ids = $the.demCollectAnsw();
				if( ! data.answer_ids ){
					Utils.demShake( $the[0] );
					return false
				}
			}

			// revote button confirmation
			if( 'delVoted' === action && ! confirm( $the.data( 'confirm-text' ) ) )
				return false

			// add visitor answer button
			if( 'newAnswer' === action ){
				$the.demAddAnswer();
				return false
			}

			// AJAX
			Loader.setLoader( $the[0] );
			jQuery.post( State.ajaxurl, data, function( respond ){
				Loader.unsetLoader( $the[0] );

				// rebind events
				$the.closest( State.screenSel ).html( respond ).demInitActions();

				// scroll to the top of the poll block
				setTimeout( function(){
					jQuery( 'html:first,body:first' ).animate( { scrollTop: $dem.offset().top - 70 }, 500 );
				}, 200 );
			} );

			return false
		};

	}

})();
